// Import necessary libraries
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.QueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.SearchHit;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;

import java.util.List;

@SpringBootApplication
public class ElasticsearchProductSearchApplication {

    @Autowired
    private RestHighLevelClient elasticsearchClient;

    public static void main(String[] args) {
        SpringApplication.run(ElasticsearchProductSearchApplication.class, args);
    }

    // Index a product
    public void indexProduct(Product product) throws Exception {
        IndexRequest request = new IndexRequest("products").id(product.getId()).source(product, XContentType.JSON);
        elasticsearchClient.index(request, RequestOptions.DEFAULT);
    }

    // Search for products
    public List<Product> searchProducts(String query) throws Exception {
        SearchRequest request = new SearchRequest("products").query(QueryBuilders.matchQuery("name", query));
        SearchResponse response = elasticsearchClient.search(request, RequestOptions.DEFAULT);

        return response.getHits().map(hit -> hit.getSourceAsObject(Product.class));
    }
}

